function solve(nums, k) {
    let totalSum = 0;
    let prefixMod = 0;
    let modCount = new Map();

    modCount.set(0, 1); // Base case: sum 0 mod k is 0, occurs once

    for (let num of nums) {
        totalSum += num;
        prefixMod = (prefixMod + num) % k;

        // If this mod has been seen before, we can remove the subarray between the previous occurrence and current
        if (modCount.has(prefixMod)) {
            // We can remove the subarray, so we don't add the current number to the total sum
            // But we need to keep track of the mod count for the remaining elements
            // So we remove the current mod count and add 1 to the mod count of the previous occurrence
            modCount.set(prefixMod, modCount.get(prefixMod) - 1);
            if (modCount.get(prefixMod) === 0) {
                modCount.delete(prefixMod);
            }
        } else {
            modCount.set(prefixMod, 1);
        }
    }

    // The minimum possible sum is the total sum minus the sum of the elements that cannot be removed
    return totalSum - (k - modCount.size) * k;
}

